#include <iostream>
// 边长数组，这样我们就不用担心数据装不下了
#include <vector>
using namespace std;
vector<int > vec;
int main() {
	int n, m;
	int t;
	cin >> n >> m;
	int index;
	while(n--) cin >> t, vec.push_back(t);
	while(m--) {
		cin >> t;
		index = lower_bound(vec.begin(), vec.end(), t) - vec.begin();
		if (t == vec[index]) cout << index + 1 << ' ';
		else cout << -1 << ' ';
	}
	return 0;
}
